const Q_ENGLISH_2000=[{"id": "objective>English>2000>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE I <br/>  <br/> Time was when boys used to point toy guns and say 'Bang!'. Now, they aim real guns and shoot one another. Nearly 4,200 teenagers were killed by firearms in 1990. Only motor vehicle accidents kill more teenagers than firearms and the firearms figures are rising. The chance that a black male between the ages of 15 and 19 will be killed by a gun has almost tripled since 1985 and almost doubled for white males, according to the National Centre for Health Statistics. <br/>  <br/> Who could disagree with Health and Human Services Secretary, Donna Shalala, when she pronounced these statistics 'frightening and intolerable?'In the shameful light of this 'waste of young lives' in Ms. Shalala's words, an often-asked question seems urgently due to be raised again: Would less violence on television – the surrounding environment for most children and young adults – make violence in actual life less normal, less accepted, less horrifying? <br/>  <br/> It may be difficult to prove an exact correlation between the viewer of fantasized violence and the criminal who acts out violence after turning off the set. But if the premise of education is granted – that good models can influence the young – then it follows that bad models can have an equivalent harmful effect. This is the reasonable hypothesis held by 80 percent of the respondents to a recent Times Mirror poll who think that violent entertainment is 'harmful' to society. <br/>  <br/> Witness enough mimed shootouts, see enough 'corpses' fall across the screen, and the taking of a human life seems no big deal. Even if a simple causal relationship cannot be established between watching violence and acting it out, is not this numbed sensitivity reason enough for cutting back on the overkill in films and TV? <br/> From <strong>The Christian Science Monitor</strong>, April 16 – 22, 1993, p. 20, CSPS, Boston, MA, USA. <br/>  <br/> The writer uses 'numbed sensitivity' to refer to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deadening of the capacity to feel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">objectionable behaviour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heartlessness on the part of actors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unreasonable violence</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deadening of the capacity to feel is the correct answer. This can be seen in the last paragraph. Basically, the author believes that desensitivization towards violence is the cause for violence. </div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE I <br/>  <br/> Time was when boys used to point toy guns and say 'Bang!'. Now, they aim real guns and shoot one another. Nearly 4,200 teenagers were killed by firearms in 1990. Only motor vehicle accidents kill more teenagers than firearms and the firearms figures are rising. The chance that a black male between the ages of 15 and 19 will be killed by a gun has almost tripled since 1985 and almost doubled for white males, according to the National Centre for Health Statistics. <br/>  <br/> Who could disagree with Health and Human Services Secretary, Donna Shalala, when she pronounced these statistics 'frightening and intolerable?'In the shameful light of this 'waste of young lives' in Ms. Shalala's words, an often-asked question seems urgently due to be raised again: Would less violence on television – the surrounding environment for most children and young adults – make violence in actual life less normal, less accepted, less horrifying? <br/>  <br/> It may be difficult to prove an exact correlation between the viewer of fantasized violence and the criminal who acts out violence after turning off the set. But if the premise of education is granted – that good models can influence the young – then it follows that bad models can have an equivalent harmful effect. This is the reasonable hypothesis held by 80 percent of the respondents to a recent Times Mirror poll who think that violent entertainment is 'harmful' to society. <br/>  <br/> Witness enough mimed shootouts, see enough 'corpses' fall across the screen, and the taking of a human life seems no big deal. Even if a simple causal relationship cannot be established between watching violence and acting it out, is not this numbed sensitivity reason enough for cutting back on the overkill in films and TV? <br/> From <strong>The Christian Science Monitor</strong>, April 16 – 22, 1993, p. 20, CSPS, Boston, MA, USA. <br/> What will actually be proved 'if the premise of education is granted'?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Entertainment on television is harmful to society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Violence on television encourages violence in real life</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Good models can influence the young</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The viewer of fantasized violence is the criminal who acts out violence</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Violence on television encourages violence in real life\" is the correct answer. This can be seen in the 3rd  paragraph. The premise, or theory is that as good models bring our positive influence in young people, bad people will also bring out negative influence.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE I <br/>  <br/> Time was when boys used to point toy guns and say 'Bang!'. Now, they aim real guns and shoot one another. Nearly 4,200 teenagers were killed by firearms in 1990. Only motor vehicle accidents kill more teenagers than firearms and the firearms figures are rising. The chance that a black male between the ages of 15 and 19 will be killed by a gun has almost tripled since 1985 and almost doubled for white males, according to the National Centre for Health Statistics. <br/>  <br/> Who could disagree with Health and Human Services Secretary, Donna Shalala, when she pronounced these statistics 'frightening and intolerable?'In the shameful light of this 'waste of young lives' in Ms. Shalala's words, an often-asked question seems urgently due to be raised again: Would less violence on television – the surrounding environment for most children and young adults – make violence in actual life less normal, less accepted, less horrifying? <br/>  <br/> It may be difficult to prove an exact correlation between the viewer of fantasized violence and the criminal who acts out violence after turning off the set. But if the premise of education is granted – that good models can influence the young – then it follows that bad models can have an equivalent harmful effect. This is the reasonable hypothesis held by 80 percent of the respondents to a recent Times Mirror poll who think that violent entertainment is 'harmful' to society. <br/>  <br/> Witness enough mimed shootouts, see enough 'corpses' fall across the screen, and the taking of a human life seems no big deal. Even if a simple causal relationship cannot be established between watching violence and acting it out, is not this numbed sensitivity reason enough for cutting back on the overkill in films and TV? <br/> From <strong>The Christian Science Monitor</strong>, April 16 – 22, 1993, p. 20, CSPS, Boston, MA, USA. <br/> From the passage, it can be inferred that since 1985</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more black males between the ages of 15 and 19 have been killing one another with guns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more black males between the ages of 15 and 19 have been getting killed by guns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more white than black males have been getting killed by guns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more black than white males have been killing one another with guns</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This can be seen in the 1st paragraph. The passage makes no reference to black males killing one another with guns, neither does it make race a focal point of the discourse.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE I <br/>  <br/> Time was when boys used to point toy guns and say 'Bang!'. Now, they aim real guns and shoot one another. Nearly 4,200 teenagers were killed by firearms in 1990. Only motor vehicle accidents kill more teenagers than firearms and the firearms figures are rising. The chance that a black male between the ages of 15 and 19 will be killed by a gun has almost tripled since 1985 and almost doubled for white males, according to the National Centre for Health Statistics. <br/>  <br/> Who could disagree with Health and Human Services Secretary, Donna Shalala, when she pronounced these statistics 'frightening and intolerable?'In the shameful light of this 'waste of young lives' in Ms. Shalala's words, an often-asked question seems urgently due to be raised again: Would less violence on television – the surrounding environment for most children and young adults – make violence in actual life less normal, less accepted, less horrifying? <br/>  <br/> It may be difficult to prove an exact correlation between the viewer of fantasized violence and the criminal who acts out violence after turning off the set. But if the premise of education is granted – that good models can influence the young – then it follows that bad models can have an equivalent harmful effect. This is the reasonable hypothesis held by 80 percent of the respondents to a recent Times Mirror poll who think that violent entertainment is 'harmful' to society. <br/>  <br/> Witness enough mimed shootouts, see enough 'corpses' fall across the screen, and the taking of a human life seems no big deal. Even if a simple causal relationship cannot be established between watching violence and acting it out, is not this numbed sensitivity reason enough for cutting back on the overkill in films and TV? <br/> From <strong>The Christian Science Monitor</strong>, April 16 – 22, 1993, p. 20, CSPS, Boston, MA, USA. <br/> The writer says 'the firearms figures are rising' because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more teenagers are now getting killed by firearms than by motor vehicle accidents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">firearms now have figures that are terribly high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more teenagers now carry firearms than used to be the case</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more teenagers are now getting killed by firearms than used to be the case</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'the firearms figures are rising' refers to the increasing number of teenagers getting killed by firearms. The passage states that 'Nearly 4,200 teenagers were killed by firearms in 1990' and that 'the firearms figures are rising', indicating that more teenagers are getting killed by firearms than used to be the case. Therefore, the correct answer is option 4.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE I <br/>  <br/> Time was when boys used to point toy guns and say 'Bang!'. Now, they aim real guns and shoot one another. Nearly 4,200 teenagers were killed by firearms in 1990. Only motor vehicle accidents kill more teenagers than firearms and the firearms figures are rising. The chance that a black male between the ages of 15 and 19 will be killed by a gun has almost tripled since 1985 and almost doubled for white males, according to the National Centre for Health Statistics. <br/>  <br/> Who could disagree with Health and Human Services Secretary, Donna Shalala, when she pronounced these statistics 'frightening and intolerable?'In the shameful light of this 'waste of young lives' in Ms. Shalala's words, an often-asked question seems urgently due to be raised again: Would less violence on television – the surrounding environment for most children and young adults – make violence in actual life less normal, less accepted, less horrifying? <br/>  <br/> It may be difficult to prove an exact correlation between the viewer of fantasized violence and the criminal who acts out violence after turning off the set. But if the premise of education is granted – that good models can influence the young – then it follows that bad models can have an equivalent harmful effect. This is the reasonable hypothesis held by 80 percent of the respondents to a recent Times Mirror poll who think that violent entertainment is 'harmful' to society. <br/>  <br/> Witness enough mimed shootouts, see enough 'corpses' fall across the screen, and the taking of a human life seems no big deal. Even if a simple causal relationship cannot be established between watching violence and acting it out, is not this numbed sensitivity reason enough for cutting back on the overkill in films and TV? <br/> From <strong>The Christian Science Monitor</strong>, April 16 – 22, 1993, p. 20, CSPS, Boston, MA, USA. <br/> In Secretary Donna Shalala's view, the situation depicted by the statistics is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tense and reassuring </div>", "<div style=\"font-family:Cambria;font-size:17px;\">topical and intimidating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alarming and unbearable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disturbing and conducive</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This can be seen in the 2nd paragraph. Her words were 'frightening and intolerable' which could be a synonym for 'alarming and unbearable'.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow. </p> <br/>  <br/>  PASSAGE II  <br/>  <br/> You would think that the common cold should be easy enough to study, but it is not so easy as it looks. Colds often seem to spread from one person to another, so it is often assumed that the cold must be infectious, but there are some puzzling observations which do not fit in with this theory. An investigator in Holland examined some eight thousand volunteers from different areas and came to the conclusion that in each group the colds all appeared at the same time – transfer of infection from case to case could not account for that. Yet at the Common Cold Research Unit in Salisbury the infection theory has been tested out; two series of about two hundred people each were inoculated, one with salt water and the other with secretions from known cold victims. Only one of the salt-water group got a cold, compared with seventy-three in the other group. <br/>  <br/> In the British Medical Journal the other day, there was a report of a meeting, 'The Common Cold - Fact and Fancy', at which one of the speakers reported a study of colds made in Cirencester over the last five years. Three hundred and fifty volunteers had kept diary records of their colds and on an average each had seven every year, with an annual morbidity of seventy days. So nearly one-fifth of our lives is spent in more or less misery, coughing and sneezing. Some widely held beliefs about the common cold have turned out not to be true. It seems that old people are just as liable to colds as the young. Sailors in isolated weather ships have just as many colds while on board and not in contact with the outside world as when on shore. It is a truism that common illnesses pose more problems than the rare. The rare disease is by comparison much easier to handle. There are not so many cases and all of them have been intensively studied. Someone has read up all the literature about the disease and published a digest of it. There will be more facts and fewer fancies. <br/>  Miles Howard; <strong>The Spectator</strong>. <br/>  <br/> Which of the following statements can be implied from the passage?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">People catch more colds in winter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The origin of colds is inconclusive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">People catch more colds in warm weather</div>", "<div style=\"font-family:Cambria;font-size:17px;\">People catch colds equally in warm and cold weather</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The passage discusses the difficulty in studying the common cold and the various theories and observations related to it. It does not provide a conclusive origin of colds, hence the statement 'The origin of colds is inconclusive' can be implied from the passage.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow. </p> <br/>  <br/>  PASSAGE II  <br/>  <br/> You would think that the common cold should be easy enough to study, but it is not so easy as it looks. Colds often seem to spread from one person to another, so it is often assumed that the cold must be infectious, but there are some puzzling observations which do not fit in with this theory. An investigator in Holland examined some eight thousand volunteers from different areas and came to the conclusion that in each group the colds all appeared at the same time – transfer of infection from case to case could not account for that. Yet at the Common Cold Research Unit in Salisbury the infection theory has been tested out; two series of about two hundred people each were inoculated, one with salt water and the other with secretions from known cold victims. Only one of the salt-water group got a cold, compared with seventy-three in the other group. <br/>  <br/> In the British Medical Journal the other day, there was a report of a meeting, 'The Common Cold - Fact and Fancy', at which one of the speakers reported a study of colds made in Cirencester over the last five years. Three hundred and fifty volunteers had kept diary records of their colds and on an average each had seven every year, with an annual morbidity of seventy days. So nearly one-fifth of our lives is spent in more or less misery, coughing and sneezing. Some widely held beliefs about the common cold have turned out not to be true. It seems that old people are just as liable to colds as the young. Sailors in isolated weather ships have just as many colds while on board and not in contact with the outside world as when on shore. It is a truism that common illnesses pose more problems than the rare. The rare disease is by comparison much easier to handle. There are not so many cases and all of them have been intensively studied. Someone has read up all the literature about the disease and published a digest of it. There will be more facts and fewer fancies. <br/>  Miles Howard; <strong>The Spectator</strong>. <br/> A rare disease can be more easily dealt with than the common cold because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">medical experts are fed up with the rampant cases of common colds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">people easily develop resistance to the common colds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adequate research exists to uncover facts about such</div>", "<div style=\"font-family:Cambria;font-size:17px;\">common colds are easily not the province of the orthodox medical experts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This can be seen towards the end of the second paragraph. It has been stated in the passage that common illnesses pose more problems than the rare. <br/> </div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow. </p> <br/>  <br/>  PASSAGE II  <br/>  <br/> You would think that the common cold should be easy enough to study, but it is not so easy as it looks. Colds often seem to spread from one person to another, so it is often assumed that the cold must be infectious, but there are some puzzling observations which do not fit in with this theory. An investigator in Holland examined some eight thousand volunteers from different areas and came to the conclusion that in each group the colds all appeared at the same time – transfer of infection from case to case could not account for that. Yet at the Common Cold Research Unit in Salisbury the infection theory has been tested out; two series of about two hundred people each were inoculated, one with salt water and the other with secretions from known cold victims. Only one of the salt-water group got a cold, compared with seventy-three in the other group. <br/>  <br/> In the British Medical Journal the other day, there was a report of a meeting, 'The Common Cold - Fact and Fancy', at which one of the speakers reported a study of colds made in Cirencester over the last five years. Three hundred and fifty volunteers had kept diary records of their colds and on an average each had seven every year, with an annual morbidity of seventy days. So nearly one-fifth of our lives is spent in more or less misery, coughing and sneezing. Some widely held beliefs about the common cold have turned out not to be true. It seems that old people are just as liable to colds as the young. Sailors in isolated weather ships have just as many colds while on board and not in contact with the outside world as when on shore. It is a truism that common illnesses pose more problems than the rare. The rare disease is by comparison much easier to handle. There are not so many cases and all of them have been intensively studied. Someone has read up all the literature about the disease and published a digest of it. There will be more facts and fewer fancies. <br/>  Miles Howard; <strong>The Spectator</strong>. <br/> According to the writer, some widely held beliefs about the common colds are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inevitable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">irreconcilable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fallacious </div>", "<div style=\"font-family:Cambria;font-size:17px;\">societal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The passage mentions that 'Some widely held beliefs about the common cold have turned out not to be true.' This implies that these beliefs are fallacious, which means false or misleading. Therefore, the correct answer is 'fallacious'.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow. </p> <br/>  <br/>  PASSAGE II  <br/>  <br/> You would think that the common cold should be easy enough to study, but it is not so easy as it looks. Colds often seem to spread from one person to another, so it is often assumed that the cold must be infectious, but there are some puzzling observations which do not fit in with this theory. An investigator in Holland examined some eight thousand volunteers from different areas and came to the conclusion that in each group the colds all appeared at the same time – transfer of infection from case to case could not account for that. Yet at the Common Cold Research Unit in Salisbury the infection theory has been tested out; two series of about two hundred people each were inoculated, one with salt water and the other with secretions from known cold victims. Only one of the salt-water group got a cold, compared with seventy-three in the other group. <br/>  <br/> In the British Medical Journal the other day, there was a report of a meeting, 'The Common Cold - Fact and Fancy', at which one of the speakers reported a study of colds made in Cirencester over the last five years. Three hundred and fifty volunteers had kept diary records of their colds and on an average each had seven every year, with an annual morbidity of seventy days. So nearly one-fifth of our lives is spent in more or less misery, coughing and sneezing. Some widely held beliefs about the common cold have turned out not to be true. It seems that old people are just as liable to colds as the young. Sailors in isolated weather ships have just as many colds while on board and not in contact with the outside world as when on shore. It is a truism that common illnesses pose more problems than the rare. The rare disease is by comparison much easier to handle. There are not so many cases and all of them have been intensively studied. Someone has read up all the literature about the disease and published a digest of it. There will be more facts and fewer fancies. <br/>  Miles Howard; <strong>The Spectator</strong>. <br/> From the information in the passage, there is evidence</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">against the theory that the common cold is infectious</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for the theory that the common cold is indeed infectious</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that old people are immune against the common cold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that medical reports are silent on facts about common colds</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The passage provides evidence for the theory that the common cold is indeed infectious. This is evident from the experiment conducted at the Common Cold Research Unit in Salisbury where two groups of people were inoculated, one with salt water and the other with secretions from known cold victims. Only one of the salt-water group got a cold, compared with seventy-three in the other group. This suggests that the common cold is infectious.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow. </p> <br/>  <br/>  PASSAGE II  <br/>  <br/> You would think that the common cold should be easy enough to study, but it is not so easy as it looks. Colds often seem to spread from one person to another, so it is often assumed that the cold must be infectious, but there are some puzzling observations which do not fit in with this theory. An investigator in Holland examined some eight thousand volunteers from different areas and came to the conclusion that in each group the colds all appeared at the same time – transfer of infection from case to case could not account for that. Yet at the Common Cold Research Unit in Salisbury the infection theory has been tested out; two series of about two hundred people each were inoculated, one with salt water and the other with secretions from known cold victims. Only one of the salt-water group got a cold, compared with seventy-three in the other group. <br/>  <br/> In the British Medical Journal the other day, there was a report of a meeting, 'The Common Cold - Fact and Fancy', at which one of the speakers reported a study of colds made in Cirencester over the last five years. Three hundred and fifty volunteers had kept diary records of their colds and on an average each had seven every year, with an annual morbidity of seventy days. So nearly one-fifth of our lives is spent in more or less misery, coughing and sneezing. Some widely held beliefs about the common cold have turned out not to be true. It seems that old people are just as liable to colds as the young. Sailors in isolated weather ships have just as many colds while on board and not in contact with the outside world as when on shore. It is a truism that common illnesses pose more problems than the rare. The rare disease is by comparison much easier to handle. There are not so many cases and all of them have been intensively studied. Someone has read up all the literature about the disease and published a digest of it. There will be more facts and fewer fancies. <br/>  Miles Howard; <strong>The Spectator</strong>. <br/> The Cirencester volunteers kept a record of their colds through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The British Medical Journal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">morbidity rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature recordings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">personal diaries</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Cirencester volunteers kept a record of their colds through 'personal diaries'. This is inferred from the line 'Three hundred and fifty volunteers had kept diary records of their colds'. The term 'diary records' implies personal diaries where they recorded instances of their colds.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE III <br/>  <br/> Young men have strong passions, and tend to gratify them indiscriminately. Of the bodily desires, it is the sexual by which they are most swayed and in which they show absence of self-control. They are changeable and fickle in their desires, which are violent while they last, but quickly over: their impulses <br/> are keen but not deep-rooted, and are like sick people's attacks of hunger and thirst. They are hot-tempered and quick-tempered, and apt to give way to their anger; bad temper often gets the better of them, for owing to their love of honour they cannot bear being slighted, and are indignant if they imagine themselves unfairly treated. While they love honour, they love victory still more, for youth is eager for superiority over others, and victory is one form of this. They love both more than they love money, which indeed they love very little, not having yet learnt what it means to be without it. They look at the good side rather than the bad, not having yet witnessed many instances of wickedness. They trust others readily, because they have not yet been cheated. They are sanguine; nature warms their blood as though with excess of wine; and besides that, they have as yet met with few disappointments. Their lives are mainly spent not in memory but in expectation, for youth has a long future before it and a short past behind it: on the first day of one's life one has nothing at all to remember, and can only look forward. They are easily cheated owing to the sanguine disposition just mentioned. Their hot tempers and hopeful dispositions make them more courageous than older men are; the hot temper prevents fear, and the hopeful disposition creates confidence; we cannot feel fear so long as we are feeling angry, and any expectation of good makes us confident. <br/>   <br/> Aristole's Youth and Old-Age, p. 197 <br/>  <br/> The expression, 'not in memory but in expectation' , as used in the passage, implies</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">innocence, not experience </div>", "<div style=\"font-family:Cambria;font-size:17px;\">future, not present</div>", "<div style=\"font-family:Cambria;font-size:17px;\">past, not present </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hopelessness, not hopefulness</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The expression, 'not in memory but in expectation', as used in the passage, implies 'innocence, not experience'. This is inferred from the lines 'Their lives are mainly spent not in memory but in expectation, for youth has a long future before it and a short past behind it: on the first day of one's life one has nothing at all to remember, and can only look forward.' This suggests that young people are more focused on the future (expectation) rather than the past (memory), and since they have not yet had many experiences, they are more innocent than experienced.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE III <br/>  <br/> Young men have strong passions, and tend to gratify them indiscriminately. Of the bodily desires, it is the sexual by which they are most swayed and in which they show absence of self-control. They are changeable and fickle in their desires, which are violent while they last, but quickly over: their impulses <br/> are keen but not deep-rooted, and are like sick people's attacks of hunger and thirst. They are hot-tempered and quick-tempered, and apt to give way to their anger; bad temper often gets the better of them, for owing to their love of honour they cannot bear being slighted, and are indignant if they imagine themselves unfairly treated. While they love honour, they love victory still more, for youth is eager for superiority over others, and victory is one form of this. They love both more than they love money, which indeed they love very little, not having yet learnt what it means to be without it. They look at the good side rather than the bad, not having yet witnessed many instances of wickedness. They trust others readily, because they have not yet been cheated. They are sanguine; nature warms their blood as though with excess of wine; and besides that, they have as yet met with few disappointments. Their lives are mainly spent not in memory but in expectation, for youth has a long future before it and a short past behind it: on the first day of one's life one has nothing at all to remember, and can only look forward. They are easily cheated owing to the sanguine disposition just mentioned. Their hot tempers and hopeful dispositions make them more courageous than older men are; the hot temper prevents fear, and the hopeful disposition creates confidence; we cannot feel fear so long as we are feeling angry, and any expectation of good makes us confident. <br/>   <br/> Aristole's Youth and Old-Age, p. 197 <br/> The statement, 'nature warms their blood as though with excess of wine', as used in the text, means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">act with considerable confidence and trust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respond with suspicion and alertness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">behave shamelessly like a drunkard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">move with care and self-control</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To be sanguine could mean to be lively and optimistic that everything will be fine. It could therefore mean to act with considerable confidence and trust.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE III <br/>  <br/> Young men have strong passions, and tend to gratify them indiscriminately. Of the bodily desires, it is the sexual by which they are most swayed and in which they show absence of self-control. They are changeable and fickle in their desires, which are violent while they last, but quickly over: their impulses <br/> are keen but not deep-rooted, and are like sick people's attacks of hunger and thirst. They are hot-tempered and quick-tempered, and apt to give way to their anger; bad temper often gets the better of them, for owing to their love of honour they cannot bear being slighted, and are indignant if they imagine themselves unfairly treated. While they love honour, they love victory still more, for youth is eager for superiority over others, and victory is one form of this. They love both more than they love money, which indeed they love very little, not having yet learnt what it means to be without it. They look at the good side rather than the bad, not having yet witnessed many instances of wickedness. They trust others readily, because they have not yet been cheated. They are sanguine; nature warms their blood as though with excess of wine; and besides that, they have as yet met with few disappointments. Their lives are mainly spent not in memory but in expectation, for youth has a long future before it and a short past behind it: on the first day of one's life one has nothing at all to remember, and can only look forward. They are easily cheated owing to the sanguine disposition just mentioned. Their hot tempers and hopeful dispositions make them more courageous than older men are; the hot temper prevents fear, and the hopeful disposition creates confidence; we cannot feel fear so long as we are feeling angry, and any expectation of good makes us confident. <br/>   <br/> Aristole's Youth and Old-Age, p. 197 <br/> The analogy between young men and sick people is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are easily swayed by emotions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are easily controlled by hunger and thirst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their emotions are active but short-lived</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are apt to give way to anger</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This can be seen towards the end of the first paragraph and at the beginning of the second paragraph. The word 'analogy' means 'similarity',that is the similarities between the attributes of young men and the sick people. the adjectives used in describing sick and young people point to fickleness of impulse. </div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE III <br/>  <br/> Young men have strong passions, and tend to gratify them indiscriminately. Of the bodily desires, it is the sexual by which they are most swayed and in which they show absence of self-control. They are changeable and fickle in their desires, which are violent while they last, but quickly over: their impulses <br/> are keen but not deep-rooted, and are like sick people's attacks of hunger and thirst. They are hot-tempered and quick-tempered, and apt to give way to their anger; bad temper often gets the better of them, for owing to their love of honour they cannot bear being slighted, and are indignant if they imagine themselves unfairly treated. While they love honour, they love victory still more, for youth is eager for superiority over others, and victory is one form of this. They love both more than they love money, which indeed they love very little, not having yet learnt what it means to be without it. They look at the good side rather than the bad, not having yet witnessed many instances of wickedness. They trust others readily, because they have not yet been cheated. They are sanguine; nature warms their blood as though with excess of wine; and besides that, they have as yet met with few disappointments. Their lives are mainly spent not in memory but in expectation, for youth has a long future before it and a short past behind it: on the first day of one's life one has nothing at all to remember, and can only look forward. They are easily cheated owing to the sanguine disposition just mentioned. Their hot tempers and hopeful dispositions make them more courageous than older men are; the hot temper prevents fear, and the hopeful disposition creates confidence; we cannot feel fear so long as we are feeling angry, and any expectation of good makes us confident. <br/>   <br/> Aristole's Youth and Old-Age, p. 197 <br/> According to the passage, young men are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">violent when they have sexual desires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">active and restive until they satisfy their desires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indignant and fickle in satisfying their sexual desires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hot-tempered when they are hungry or thirsty</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the passage, young men are described as being changeable and fickle in their desires, which includes their sexual desires. They are also described as being hot-tempered and quick-tempered, but this is not specifically linked to them being hungry or thirsty. Therefore, the correct answer is 'indignant and fickle in satisfying their sexual desires'.</div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Read this passage carefully and answer the questions that follow.</p> <br/>  <br/>  PASSAGE III <br/>  <br/> Young men have strong passions, and tend to gratify them indiscriminately. Of the bodily desires, it is the sexual by which they are most swayed and in which they show absence of self-control. They are changeable and fickle in their desires, which are violent while they last, but quickly over: their impulses <br/> are keen but not deep-rooted, and are like sick people's attacks of hunger and thirst. They are hot-tempered and quick-tempered, and apt to give way to their anger; bad temper often gets the better of them, for owing to their love of honour they cannot bear being slighted, and are indignant if they imagine themselves unfairly treated. While they love honour, they love victory still more, for youth is eager for superiority over others, and victory is one form of this. They love both more than they love money, which indeed they love very little, not having yet learnt what it means to be without it. They look at the good side rather than the bad, not having yet witnessed many instances of wickedness. They trust others readily, because they have not yet been cheated. They are sanguine; nature warms their blood as though with excess of wine; and besides that, they have as yet met with few disappointments. Their lives are mainly spent not in memory but in expectation, for youth has a long future before it and a short past behind it: on the first day of one's life one has nothing at all to remember, and can only look forward. They are easily cheated owing to the sanguine disposition just mentioned. Their hot tempers and hopeful dispositions make them more courageous than older men are; the hot temper prevents fear, and the hopeful disposition creates confidence; we cannot feel fear so long as we are feeling angry, and any expectation of good makes us confident. <br/>   <br/> Aristole's Youth and Old-Age, p. 197 <br/> The writer says that young people are optimistic in their dealings with people because they are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steadfast </div>", "<div style=\"font-family:Cambria;font-size:17px;\">courageous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discreet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reckless</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This can be seen towards the end of the passage. This is the accurate answer <br/> </div>", "topic": "COMPREHENSION PASSAGE"}, {"id": "objective>English>2000>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/>  <br/> ...1...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judicial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">administrative  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislative</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This best suits because the senate has to do with the legislative arm and they are saddled with responsibility of law making.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...2...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enforce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nullify</div>", "<div style=\"font-family:Cambria;font-size:17px;\">modify</div>", "<div style=\"font-family:Cambria;font-size:17px;\">order</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The context of the passage suggests that the Senate is trying to 'nullify' the executive action of the President. 'Nullify' means to make legally null and void; invalidate. The Senate, being a legislative body, does not have the power to enforce, modify, or order the executive action of the President.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...3...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a wing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a portion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an anchor </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an arm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This best suits the context. This is the accurate answer. <br/> </div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...4...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">House of Representatives </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Assembly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Executive Council</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the passage, the author is discussing the potential confusion that could arise if another part of the National Assembly were to disagree with the Senate. The House of Representatives is another part of the National Assembly, making it the correct answer. The Judiciary and the Executive Council are separate branches of government and do not fit the context of the sentence.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...5...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">litigant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">defendant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plaintiff </div>", "<div style=\"font-family:Cambria;font-size:17px;\">attorney</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the passage, the Senate is being criticized for overstepping its bounds and acting as both the 'litigant' and the judge of the constitutionality of the President's actions. A 'litigant' is a party involved in a lawsuit, which fits the context better than the other options. 'Defendant' and 'plaintiff' are specific types of litigants, but the passage does not specify which role the Senate is taking on. 'Attorney' does not fit because the Senate is not representing someone in a legal matter, but rather taking on the role of a party in a lawsuit.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...6... </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enact</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create </div>", "<div style=\"font-family:Cambria;font-size:17px;\">compose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">annul</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the passage, the function of the Senate is to 'enact' laws. To 'enact' a law means to make it official or put it into action, which is the role of legislative bodies like the Senate. 'Create' could also work, but 'enact' is more specific to the process of passing laws. 'Compose' is more commonly used in the context of writing or creating something like a piece of music or literature, not laws. 'Annul' means to declare invalid, which is not a function of the Senate mentioned in the passage.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...7...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">might </div>", "<div style=\"font-family:Cambria;font-size:17px;\">power </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dynamism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">strength</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the passage, the Senate does not have the authority or 'power' to control the President in the exercise of his powers. The term 'power' refers to the ability or capacity to do something or act in a particular way. The other options 'might', 'dynamism', and 'strength' do not fit into the context of the sentence.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...8...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">official </div>", "<div style=\"font-family:Cambria;font-size:17px;\">authoritative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judicial </div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the passage, the President is exercising his 'executive' powers. The term 'executive' refers to the branch of government responsible for implementing, administering, and enforcing laws. The other options 'official', 'authoritative', and 'judicial' do not fit into the context of the sentence.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...9... </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">modified</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standardized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">regulated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordered </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the passage, the exercise of the powers of the President can be 'regulated'. This means that the actions of the President can be controlled or governed according to a system or set of rules, which is the role of the National Assembly. The other options do not fit into the context of the passage.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">The passage below has gaps. Immediately following each gap, four options are provided. Choose the most appropriate option for each gap.</p> <br/>   <br/>  PASSAGE IV  <br/>  <br/> With the most profound respect to the members of the Senate, I do not think that it is within the competence of that ...1... body to pass a motion to ...2... the executive action of the President. The Senate is ...3... of the National Assembly. But it is not by itself alone the National Assembly. One can imagine the confusion, which would be created if the ...4... were to take a view diametrically opposed to that reflected in the Senate resolution. The strongest objection to the action of the Senate in passing the resolution is the fact that it constituted itself the ...5... as well as the judge of the constitutionality of the action of the President. The function of the Senate is to ...6... laws. But the Senate has no authority or ...7... to control the President in the exercise of his ...8... powers. It cannot by a mere resolution or motion give any directive to the President regarding the exercise of his powers nor can it undo what the President has done in the exercise of those powers. The only way in which the exercise of the powers of the President can be ...9...  is by ...10... of the National Assembly.  <br/>  Adapted from The Guardian of July 8, 1999, p. 8. <br/> ...10...</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an Act </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a Decree</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a motion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the passage, the exercise of the powers of the President can be regulated by 'an Act' of the National Assembly. An Act is a law that has been officially put into effect, which fits into the context of the passage. The other options do not fit into the context of the passage.</div>", "topic": "CLOZE PASSAGE"}, {"id": "objective>English>2000>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">LEXIS,STRUCTURE AND ORAL FORMS  <br/>  In this questions, choose the option that has the same vowel sound as the one represented by the letters.</p> <br/>  <br/> b<span style=\"text-decoration:underline;\">oa</span>t</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">board </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bought</div>", "<div style=\"font-family:Cambria;font-size:17px;\">go </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glory</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The words are pronounced thus: boat /bəʊt/, go /ɡəʊ/; the remaining three have the vowel /ɔː/.</div>", "topic": "ORAL FORMS : VOWELS"}, {"id": "objective>English>2000>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">LEXIS,STRUCTURE AND ORAL FORMS  <br/>  In this questions, choose the option that has the same vowel sound as the one represented by the letters.</p>  <br/>  <br/> <span style=\"text-decoration:underline;\">ai</span>r</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heir </div>", "<div style=\"font-family:Cambria;font-size:17px;\">her</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hear </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fire</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word \"air\" /eə(r)/ is pronounced the same way as \"heir\" /eə(r)/. Thus, they are homophones. Others are pronounced \"her\" /hɜː/, <br/> \"here\" /hɪə/ and \"fire\" /faɪə/.</div>", "topic": "ORAL FORMS : VOWELS"}, {"id": "objective>English>2000>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">LEXIS,STRUCTURE AND ORAL FORMS  <br/>  In this questions, choose the option that has the same vowel sound as the one represented by the letters.</p>  <br/>  <br/> pl<span style=\"text-decoration:underline;\">ea</span>sure</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pliable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pleat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plenary </div>", "<div style=\"font-family:Cambria;font-size:17px;\">jeopardy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vowel sound in 'pleasure' is represented by 'ea'. This sound is similar to the 'e' sound in 'plenary'. Therefore, 'plenary' is the correct answer.</div>", "topic": "ORAL FORMS : VOWELS"}, {"id": "objective>English>2000>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">LEXIS,STRUCTURE AND ORAL FORMS  <br/>  In this questions, choose the option that has the same vowel sound as the one represented by the letters.</p>  <br/>  <br/> thund<span style=\"text-decoration:underline;\">er</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prefer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">differ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">confer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">defer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vowel sound in 'thunder' is represented by 'er'. This sound is similar to the 'er' sound in 'differ'. Therefore, 'differ' is the correct answer.</div>", "topic": "ORAL FORMS : VOWELS"}, {"id": "objective>English>2000>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">LEXIS,STRUCTURE AND ORAL FORMS  <br/>  In this questions, choose the option that has the same vowel sound as the one represented by the letters.</p>  <br/>  <br/> t<span style=\"text-decoration:underline;\">ea</span>r (noun)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dare</div>", "<div style=\"font-family:Cambria;font-size:17px;\">care</div>", "<div style=\"font-family:Cambria;font-size:17px;\">here </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wear</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'tear' (noun) has the same vowel sound as 'wear'. In phonetics, the vowel sound in these words is represented as /ɪə/. This sound is a centering diphthong, which is a combination of two vowel sounds within the same syllable.</div>", "topic": "ORAL FORMS : VOWELS"}, {"id": "objective>English>2000>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this questions, choose from the options the word that has the same consonant sound as the one represented by the letters underlined.</p> <br/>  <br/> <span style=\"text-decoration:underline;\">th</span>ought</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">theatre </div>", "<div style=\"font-family:Cambria;font-size:17px;\">taught</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weather</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'thought' has the same consonant sound as 'taught'. The 'th' in both words is a voiceless dental fricative, represented as /θ/ in phonetics. This sound is produced by placing the tip of the tongue against the upper teeth and blowing air out of the mouth.</div>", "topic": "ORAL FORMS : CONSONANTS"}, {"id": "objective>English>2000>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose from the options the word that has the same consonant sound as the one represented by the letters underlined.</p>  <br/>  <br/> cali<span style=\"text-decoration:underline;\">ph</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">presently </div>", "<div style=\"font-family:Cambria;font-size:17px;\">perhaps</div>", "<div style=\"font-family:Cambria;font-size:17px;\">powerful</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opponent</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The consonant sound represented by the letters 'ph' in 'caliph' is /f/. The word 'powerful' also has the same /f/ sound represented by 'ph'.</div>", "topic": "ORAL FORMS : CONSONANTS"}, {"id": "objective>English>2000>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this questions, select the word that has the same pattern of stress as the given word.</p> <br/>  <br/> ENORMOUS</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stupidly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">character</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'ENORMOUS' has a stress pattern of 1-0-0 (EN-or-mous). The word 'stupidly' also has the same stress pattern of 1-0-0 (STU-pid-ly).</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, select the word that has the same pattern of stress as the given word.</p>  <br/>  <br/> HONOUR</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hotel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hyena</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human </div>", "<div style=\"font-family:Cambria;font-size:17px;\">humane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The given word is stressed on the first syllable as HOnour which has the same pattern as option HUman.</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, select the word that has the same pattern of stress as the given word.</p>  <br/>  <br/> QUALITY</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">guarantee </div>", "<div style=\"font-family:Cambria;font-size:17px;\">accepted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bachelor </div>", "<div style=\"font-family:Cambria;font-size:17px;\">relation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'QUALITY' has its stress on the first syllable. Among the options, the word 'relation' also has its stress on the second syllable, hence it has the same stress pattern as 'QUALITY'.</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, select the word that has the same pattern of stress as the given word.</p>  <br/>  <br/> EDUCATION</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">duplicity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elaborate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">conjectural</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both eduCAtion and ecoNOmics are stressed on the penultimate syllable (the second-last syllable). Others are not stressed on the penultimate syllable.</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this question, identify the word that has the stress on the second syllable.</p> <br/>  <br/> The word is ...... </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reproduce </div>", "<div style=\"font-family:Cambria;font-size:17px;\">always</div>", "<div style=\"font-family:Cambria;font-size:17px;\">result</div>", "<div style=\"font-family:Cambria;font-size:17px;\">understand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the word 'result', the stress is on the second syllable, pronounced as /rɪˈzʌlt/. Therefore, 'result' is the word that has the stress on the second syllable.</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, identify the word that has the stress on the second syllable.</p>  <br/>  <br/> The word is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tomato </div>", "<div style=\"font-family:Cambria;font-size:17px;\">photograph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yesterday </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tranquil</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In English phonetics, stress is the relative emphasis that may be given to certain syllables in a word. The word 'photograph' has the stress on the second syllable. The pronunciation is /fəˈtɒɡrɑːf/, where the 'ˈ' before the second syllable indicates the stress.</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this question, identify the word that has a different stress pattern from the others.</p> <br/>  <br/> The word is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">integral </div>", "<div style=\"font-family:Cambria;font-size:17px;\">intimate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discourse </div>", "<div style=\"font-family:Cambria;font-size:17px;\">accelerate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In English phonetics, different words have different stress patterns. The words 'integral', 'intimate', and 'discourse' all have the stress on the first syllable. However, the word 'accelerate' has the stress on the second syllable. Therefore, 'accelerate' has a different stress pattern from the others.</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, identify the word that has a different stress pattern from the others.</p>  <br/>  <br/> The word is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">navigate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">envelop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word is <strong>envelop</strong>. It is stressed on the penultimate (second-last) syllable while the others are stressed on the antepenultimate (third-last) syllable</div>", "topic": "ORAL FORMS : STRESS PATTERN"}, {"id": "objective>English>2000>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p> <br/>  <br/> Without our relentless campaigns, we might ...... sure of victory in the race for the National Assembly.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">never have been </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have never be</div>", "<div style=\"font-family:Cambria;font-size:17px;\">never had been </div>", "<div style=\"font-family:Cambria;font-size:17px;\">be never</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>never have been</strong> is most appropriate. Because of the use of the modal \"might,\" the form of anomalous HAVE to use is <strong>have</strong>. Then, after \"have\" comes the past participle \"been\".</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> We are all hungry; we ...... anything to eat since morning.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">didn't have </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hadn't had </div>", "<div style=\"font-family:Cambria;font-size:17px;\">haven't had</div>", "<div style=\"font-family:Cambria;font-size:17px;\">never had</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>haven't had</strong> is most appropriate. This is known as the present perfect tense which is used to show that an action has been completed (or not) as of the time of speaking.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> To check desertification in the arid zones, ...... trees should be planted.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drought-proof </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drought-resisting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drought-effective </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drought-resistant</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>drought-resistant</strong> is most appropriate. Drought tolerance refers to the degree to which a plant is adapted to arid or drought conditions. </div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The loquacious young lad reeled off all the names of the players ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">off head </div>", "<div style=\"font-family:Cambria;font-size:17px;\">offhand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at heart </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at hand</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'offhand' is used to describe something done without preparation or forethought. In this context, it means the young lad was able to reel off the names of the players without needing to think about it or prepare beforehand.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> I like the character that played the role of a political ...... at the last convention of our party.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thorncoat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">torncoat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">turncoat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">turnedcoat</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>turncoat </strong> is most appropriate. A turncoat is a person who deserts one party or cause in order to join an opposing one.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> All the traders in the market saw the woman buy ...... the imported suits.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">up </div>", "<div style=\"font-family:Cambria;font-size:17px;\">off </div>", "<div style=\"font-family:Cambria;font-size:17px;\">over </div>", "<div style=\"font-family:Cambria;font-size:17px;\">out</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>up</strong> is most appropriate. The phrasal verb \"buy up\" means to buy all or as much as possible of something.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The man declared his intention from the ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">outset </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inset </div>", "<div style=\"font-family:Cambria;font-size:17px;\">onset </div>", "<div style=\"font-family:Cambria;font-size:17px;\">offset</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct phrase is 'from the outset'. 'From the outset' means from the beginning. So, in the context of the sentence, 'from the outset' is the most appropriate option.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The Team Manager told us that the race could only be won by the ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">flat-footed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bare-footed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">swift-footed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fore-footed</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'swift-footed' is used to describe someone who can run fast. In the context of a race, it makes sense that the Team Manager would say the race could only be won by the 'swift-footed' as it implies the race could only be won by someone who can run fast.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The Governor rejected the bill and withheld his ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">assent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">access </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ascent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct word to use in this context is 'assent'. 'Assent' means to agree to or approve something officially. In this case, the Governor rejected the bill and withheld his 'assent', meaning he did not give his approval.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The new school is not provided with ...... for science practical.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enough equipment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equipments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an equipment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">enough equipments</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>enough equipment</strong> is most appropriate. The word \"equipment\" is non-count and thus, should never take an indefinite article (a/an) nor the plural form (-s).</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>51", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> Much as I would love to visit him, I'm afraid ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I won't </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I can't </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I can't be able </div>", "<div style=\"font-family:Cambria;font-size:17px;\">of visiting him</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>I can't</strong> is most appropriate. It means while the speaker has the ability to and would like to visit him, he or she has made a decision not to do so.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>52", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> Ilesa witnessed the largest ...... of writers at any convention in recent times.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">turn-around </div>", "<div style=\"font-family:Cambria;font-size:17px;\">turnover </div>", "<div style=\"font-family:Cambria;font-size:17px;\">turn-out </div>", "<div style=\"font-family:Cambria;font-size:17px;\">turn-on</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct phrase to use in this context is 'turn-out'. 'Turn-out' refers to the number of people who attend a particular event. Therefore, in the context of the sentence, 'turn-out' is the most appropriate word to use when talking about the number of writers at a convention.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>53", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The warring factions need words of ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advise </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adverse </div>", "<div style=\"font-family:Cambria;font-size:17px;\">advises </div>", "<div style=\"font-family:Cambria;font-size:17px;\">advice</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>advice</strong> is most appropriate. The correct option \"advice\" is a noun which should come after the preposition \"of\".</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>54", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The politicians were ...... by the press.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marooned </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ridiculed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">eclipsed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ostracized</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct word to fill in the gap is 'ridiculed'. The sentence implies that the politicians were made fun of or mocked by the press. 'Ridiculed' is the most appropriate word to use in this context. 'Marooned' means left isolated or alone, 'eclipsed' means obscured or overshadowed, and 'ostracized' means excluded or made to feel unwelcome. None of these words fit the context of the sentence as well as 'ridiculed' does.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>55", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> There are many ...... to her personality.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">styles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">facets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">faces</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct word to fill in the gap is 'facets'. The sentence implies that there are many aspects or sides to her personality. 'Facets' is the most appropriate word to use in this context. 'Moods' and 'styles' could potentially work, but they are not as precise as 'facets'. 'Faces' is not the correct term to use when talking about aspects of personality.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>56", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> There are several ...... in the farmyard.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sheep </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ewe </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lamb </div>", "<div style=\"font-family:Cambria;font-size:17px;\">goat</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>sheep</strong> is most appropriate. Sheep is both singular and plural. According to the law of pluralia tantums, some nouns seem singular but are actually plural, and there are some that seem to be plural but they are singular.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>57", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> Audu fought with his ...... brother.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">senior </div>", "<div style=\"font-family:Cambria;font-size:17px;\">older </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bigger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">elder</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sentence 'Audu fought with his ...... brother.' requires a term that indicates a relative age difference between Audu and his brother. The most appropriate word to fill the gap is 'older' because it directly indicates that Audu's brother is of a greater age than Audu. 'Senior' can refer to a position of authority or respect, 'bigger' refers to size, and 'elder' is a more formal term that is less commonly used in this context. Therefore, the correct answer is option 2, 'older'.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>58", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> The Dark Continent was an ...... for Africa.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">abuse </div>", "<div style=\"font-family:Cambria;font-size:17px;\">enigma </div>", "<div style=\"font-family:Cambria;font-size:17px;\">eclectic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">epithet</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>epithet</strong> is most appropriate. It is an adjective or phrase expressing a quality or attribute regarded as characteristic of the person or thing mentioned.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>59", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> He arrived ...... to see his family leave for the countryside.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in time </div>", "<div style=\"font-family:Cambria;font-size:17px;\">timely </div>", "<div style=\"font-family:Cambria;font-size:17px;\">late </div>", "<div style=\"font-family:Cambria;font-size:17px;\">with time</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>in time</strong> is most appropriate. It means not late; with enough time to be able to do something.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>60", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> You can travel on your own, ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isn't it </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wouldn't you</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can't you </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shouldn't you</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>can't you </strong> is most appropriate. The auxiliary \"can\" should be used together with \"not\" to form the question tag.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>61", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> Our culture does not allow one to ...... when an elderly person is speaking.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cut of </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cut off </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cut in </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cut on</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>cut in</strong> is most appropriate. It is the phrasal verb of cut. It means to interrupt someone while they are speaking.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>62", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, fill each gap with the most appropriate option from the list provided.</p>  <br/>  <br/> Raffle draws like gambling often end in a ...... for me.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loss </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lose</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'loss'. In the context of the sentence, the speaker is referring to a negative outcome from participating in raffle draws or gambling. The word 'loss' is a noun that refers to the fact or process of losing something or someone, in this case, probably money or assets in gambling. The other options 'lost', 'loose', and 'lose' do not fit grammatically in the sentence.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE COMPLETION"}, {"id": "objective>English>2000>63", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this question, select the option that best explains the information conveyed in the sentence.</p> <br/>  <br/> If he were here, it could be more fun.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">He did not show up and so the occasion lacked much fun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">He was being expected to supply more fun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There was no fun because he was not present</div>", "<div style=\"font-family:Cambria;font-size:17px;\">He was expected but did not show up to liven up the occasion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'He did not show up and so the occasion lacked much fun'. The sentence 'If he were here, it could be more fun' is a hypothetical condition which implies that the person being referred to is not present, and his presence could have made the situation more enjoyable. The other options do not fully capture the essence of the sentence.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE INTERPRETATION"}, {"id": "objective>English>2000>64", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, select the option that best explains the information conveyed in the sentence.</p>  <br/>  <br/> Though he is our elected representative, he often takes a rather jaundiced view of our problems.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">He takes a rather hazy view of our problems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">He takes an unfavourable position concerning our problems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">He takes a rather forceful view of our problems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">He takes a sickly view of our problems</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'jaundiced view' is an idiomatic expression that means having a cynical or sceptical view of something. It does not mean hazy, forceful or sickly. Therefore, the option that best explains the information conveyed in the sentence is 'He takes an unfavourable position concerning our problems'.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE INTERPRETATION"}, {"id": "objective>English>2000>65", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, select the option that best explains the information conveyed in the sentence.</p>  <br/>  <br/> When I visited James I only gave him a congratulatory card on account of his promotion.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The only person I visited was James and nobody else</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It was only James that I gave a congratulatory card to</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All I gave James when I visited him was a congratulatory card</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All I did when I visited James was given a congratulatory card</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'on account of his promotion' indicates that the reason for giving the congratulatory card was James's promotion. The sentence 'When I visited James I only gave him a congratulatory card on account of his promotion' implies that the only thing the speaker did for James during the visit was to give him a congratulatory card. Therefore, the option that best explains the information conveyed in the sentence is 'All I gave James when I visited him was a congratulatory card'.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE INTERPRETATION"}, {"id": "objective>English>2000>66", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, select the option that best explains the information conveyed in the sentence.</p>  <br/>  <br/> The events of last Friday show that there is no love lost between the Principal and the Vice-Principal.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They like each other </div>", "<div style=\"font-family:Cambria;font-size:17px;\">They work independently</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They cannot part company </div>", "<div style=\"font-family:Cambria;font-size:17px;\">They dislike each other</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'no love lost between' is an idiom that means the two people mentioned have a mutual dislike for each other. Therefore, the Principal and the Vice-Principal dislike each other.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE INTERPRETATION"}, {"id": "objective>English>2000>67", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, select the option that best explains the information conveyed in the sentence.</p>  <br/>  <br/> The politician's inflammatory remarks were heavily criticized.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The politician's rude remarks were heavily criticized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The politician's provocative remarks were heavily criticized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The politician's bombastic remarks were heavily criticized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The politician's tribalistic remarks were heavily criticized</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inflammatory remarks refer to comments that are intended to stir up or incite strong reactions or emotions, often negative. Therefore, the politician's remarks were provocative, intended to provoke or incite, which is why they were heavily criticized.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE INTERPRETATION"}, {"id": "objective>English>2000>68", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p> <br/>  <br/> The Governor told the chief that he was only on a <em>routine</em> tour.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normal and regular visit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unplanned encounter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surprise and impromptu check </div>", "<div style=\"font-family:Cambria;font-size:17px;\">working visit and homage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'routine' in the context of the sentence implies something that is regular or normal. Therefore, the option 'normal and regular visit' is the closest in meaning.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>69", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The boy was told that he would need <em>several</em> more pints of blood if he was to survive.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">many </div>", "<div style=\"font-family:Cambria;font-size:17px;\">much </div>", "<div style=\"font-family:Cambria;font-size:17px;\">some </div>", "<div style=\"font-family:Cambria;font-size:17px;\">plenty</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'several' in the context of the sentence implies a certain but unspecified number, which is more than a few but not a lot. Therefore, the option 'many' is the closest in meaning.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>70", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The Principal told the teacher to stop <em>browbeating</em> the children.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pampering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bullying </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deceiving </div>", "<div style=\"font-family:Cambria;font-size:17px;\">caning</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'browbeating' means to intimidate or bully. Therefore, the option that is nearest in meaning to 'browbeating' is 'bullying'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>71", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> Some actions of the Nigerian youth have <span style=\"text-decoration:underline;\">alienated</span> them from those who were <em>sympathetic</em> to their cause.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">endeared/kindly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">confronted/ill disposed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">separated/opposed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">estranged/well disposed</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'alienated' means to cause someone to feel isolated or estranged. Therefore, the option that is nearest in meaning to 'alienated' is 'estranged'. Similarly, 'sympathetic' means showing approval, favor or sympathy, hence the closest meaning is 'well disposed'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>72", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The essay topic is <em>nebulous</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vague </div>", "<div style=\"font-family:Cambria;font-size:17px;\">incorrect </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distinct </div>", "<div style=\"font-family:Cambria;font-size:17px;\">clear</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'nebulous' means unclear, vague, or ill-defined. Therefore, the option 'vague' is the closest in meaning.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>73", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The man was able to persuade his <em>willful and obstinate daughter</em> to follow the career he chose for her.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">intelligent but arrogant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unyielding and obdurate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obscure and odious </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hardworking and intelligent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'willful and obstinate' refers to someone who is stubbornly adhering to an attitude, opinion, or course of action. Therefore, the option 'unyielding and obdurate' is the closest in meaning. 'Obdurate' is a synonym for 'obstinate', both meaning stubbornly refusing to change one's opinion or course of action.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>74", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> Mr. Okon has been described as an <em>eagle-eyed editor</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a short-sighted </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a clear-sighted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a long-sighted </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a quick-sighted</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'eagle-eyed' is often used to describe someone who has a keen or sharp sight, or someone who pays great attention to details. In this context, it is used to describe Mr. Okon's ability as an editor. The option 'a clear-sighted' is the closest in meaning to 'eagle-eyed'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>75", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> In spite of her grim situation, the young widow smiled dutifully at the visitor's <em>pleasantries</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unkind comments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sad stories</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condolence messages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">jocular remarks</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term 'pleasantries' refers to polite conversation or light-hearted comments or remarks. In this context, it is used to describe the visitor's comments. The option 'jocular remarks' is the closest in meaning to 'pleasantries'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>76", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> I have always believed that my mother is a very <em>impassioned</em> woman.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">emotive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impartial </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impassive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emotional</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'impassioned' means showing or filled with intense emotion or passion. Therefore, the word that is nearest in meaning to 'impassioned' is 'emotional'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>77", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The party gathering was thrown into a state of <em>euphoria</em> after the election result was announced.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pleasure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sadness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excitement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">confusion</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'euphoria' refers to a feeling or state of intense excitement and happiness. Therefore, the word that is nearest in meaning to 'euphoria' is 'excitement'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>78", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The family discussed the crime committed and resolved to <em>nail the lie to the counter</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">expose it publicly. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bury it in a coffin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defer action on it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seek more advice</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'nail the lie to the counter' is an idiomatic expression which means to expose a lie or deception. Therefore, the option 'expose it publicly' is the closest in meaning.</div>", "topic": "LEXIS AND STRUCTURE : SENTENCE INTERPRETATION"}, {"id": "objective>English>2000>79", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> My father was at the <em>apogee</em> of his career when he was retired.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">terminal point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">highest point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">least productive stage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">redundant stage</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'apogee' refers to the highest point in the development of something; the climax or culmination. Therefore, the option 'highest point' is the closest in meaning.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>80", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> Though David's condition is <em>serious</em>, his life is not in immediate danger.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nasty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypertensive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dangerous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">grave</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Serious as used in this context, could means grave. Which is seriousness in a negative sense, specifically referring to a physical state of a being or an event. </div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>81", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> That punch by the young boxer proved to be <em>fatal</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">effective </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hard </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deadly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">belated</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of the sentence, 'fatal' refers to something causing death. Therefore, the word 'deadly' is the nearest in meaning to 'fatal'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>82", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The presence of the security men in the area will provide a <em>moment of respite</em> for the residents.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soothing relaxation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">enduring reprieve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lasting security </div>", "<div style=\"font-family:Cambria;font-size:17px;\">temporary relief</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'moment of respite' refers to a short period of rest or relief from something difficult or unpleasant. Therefore, the option 'temporary relief' is the closest in meaning to the phrase.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>83", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> It is time for all concerned to first <em>pick to pieces</em> the strike action before proffering solutions.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">embrace joyfully </div>", "<div style=\"font-family:Cambria;font-size:17px;\">critically analyse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stop abruptly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">commend highly</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'pick to pieces' means to criticize or find fault with something in a detailed and merciless way. Therefore, the option 'critically analyse' is the closest in meaning to the phrase.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>84", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this questions, choose the option nearest in meaning to the word(s) or phrase in italics. </p>  <br/>  <br/> The new ruler is <em>big-hearted</em> in his dealings with the people.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">generous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cruel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soft </div>", "<div style=\"font-family:Cambria;font-size:17px;\">proud</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'big-hearted' is often used to describe someone who is generous or kind. In this context, it means that the ruler is generous in his dealings with the people. Therefore, the option that is nearest in meaning to 'big-hearted' is 'generous'.</div>", "topic": "LEXIS AND STRUCTURE : SYNONYMS"}, {"id": "objective>English>2000>85", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p> <br/>  <br/> The teacher announced that the class would be making a <em>fleeting</em> visit to the zoo.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">routine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">brief </div>", "<div style=\"font-family:Cambria;font-size:17px;\">long </div>", "<div style=\"font-family:Cambria;font-size:17px;\">guided</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'fleeting' means lasting for a very short time. Therefore, the word that is opposite in meaning to 'fleeting' is 'long'. In this context, a 'fleeting' visit to the zoo would be a short visit, so the opposite would be a 'long' visit.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>86", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> The project is designed to <em>alleviate</em> poverty in the country.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tackle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exacerbate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">eradicate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">assuage</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'alleviate' means to make something less severe. The opposite of 'alleviate' would be to make something more severe or worse, which is what 'exacerbate' means. Therefore, the correct answer is option 2, 'exacerbate'.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>87", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> Civil engineering is <em>predominantly</em> a male profession.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absolutely </div>", "<div style=\"font-family:Cambria;font-size:17px;\">essentially </div>", "<div style=\"font-family:Cambria;font-size:17px;\">generally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seldomly</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'predominantly' means mainly or for the most part. The opposite of 'predominantly' would be 'rarely' or 'seldomly'. Therefore, the correct answer is option 4, 'seldomly'.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>88", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> The officer said that he knew nothing to the <em>detriment</em> of the applicant.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">damage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disfavour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">advantage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">background</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'detriment' refers to harm or damage. Therefore, the opposite of 'detriment' would be 'advantage', which means a condition or circumstance that puts one in a favorable or superior position.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>89", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> When the driver applied the brakes, they <em>acted up</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">failed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">responded well </div>", "<div style=\"font-family:Cambria;font-size:17px;\">were sluggish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">jammed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Respoded well is the most appropriate response. To act up is to behave badly or to not work as it should.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>90", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> The striking workers have vowed not to return to work until the decision is <em>rescinded</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">changed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dismissed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">implemented</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incorporated</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'rescinded' means to revoke, cancel, or repeal (a law, order, or agreement). Therefore, the opposite of 'rescinded' would be 'implemented', which means to put (a decision, plan, agreement, etc.) into effect.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>91", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> It is rare for a leader and his deputy to see <em>eye to eye</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disagree </div>", "<div style=\"font-family:Cambria;font-size:17px;\">respect each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be of one mind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproach each other</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To see eye to eye means to share the same views as somebody about something. The opposite is to disagree.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>92", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> Common sense requires that one should be <em>decorous</em> at formal gatherings.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">courteous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impolite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incurious </div>", "<div style=\"font-family:Cambria;font-size:17px;\">careful</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'decorous' means behaving politely and in a controlled way, especially in a social situation. Therefore, the opposite of 'decorous' is 'impolite' which means not having or showing good manners; rude.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>93", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> The diminutive figure bounces over the track with <em>unfathomable</em> lightness.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">invigorating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">irresistible </div>", "<div style=\"font-family:Cambria;font-size:17px;\">predictable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">impressive</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unfathomable means incapable of being fully explored or understood. The opposite word will be predictable.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>94", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> I'm not interested in buying that shirt. I think it is <em>overpriced</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">too expensive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">overrated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">priceless</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheap</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'overpriced' simply means when something is too expensive or is of exorbitant price <br/> The opposite will be 'cheap'</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>95", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> Despite his laxity in other matters, Ojo's father <em>drew the line</em> at truancy.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">favoured </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rejected</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emphasized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ignored</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phrase 'drew the line' means to set a limit or boundary, to not allow something. In this context, Ojo's father did not allow truancy. The opposite of this would be to allow or ignore something, which is represented by the word 'ignored'.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>96", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> The string was <em>taut</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">firm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stretched </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tight</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taut means firm or very tight which can be very difficult to loose. The opposite word will be loose.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>97", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> Hypertension is a <em>debilitating</em> disease that everyone should prevent.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a mortal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an enervating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an energizing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a horrible</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It means to make someone very weak and infirm. The opposite word will be energising, to give energy.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>98", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> The Permanent Secretary left his job <em>under a cloud</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">on a cloudy day  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">with a clear record</div>", "<div style=\"font-family:Cambria;font-size:17px;\">in disgrace </div>", "<div style=\"font-family:Cambria;font-size:17px;\">on a sunny day</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To leave <strong>under a cloud</strong> means to leave in suspicion or discredited. Leaving with a clear record will be the opposite phrase.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>99", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> We intend to make the reception a <em>diurnal</em> event.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a nightly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a weekly </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a short </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an annual</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The word 'diurnal' means happening during the day or daily. The opposite of this would be 'a nightly', which means happening during the night.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}, {"id": "objective>English>2000>100", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">In this question, choose the option opposite in meaning to the word(s) or phrase in italics.</p>  <br/>  <br/> It is surprising that this politician has now turned <em>renegade</em>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">militant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">corrupt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loyal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quiet</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A renegade is one who rejects a religion, cause, allegiance, or group for another; a deserter. The opposite word will be loyal.</div>", "topic": "LEXIS AND STRUCTURE : ANTONYMS"}];
